from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
import random
import pyotp

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Sample user database
users = {
    "user@example.com": {
        "password": generate_password_hash("password123"),
        "mfa_enabled": True,
        "mfa_secret": pyotp.random_base32()
    }
}

# Simulate a database for OTPs
otps = {}

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    email = data['email']
    password = data['password']

    user = users.get(email)
    if user and check_password_hash(user['password'], password):
        if user['mfa_enabled']:
            otp = pyotp.TOTP(user['mfa_secret']).now()
            otps[email] = otp  # Store OTP temporarily
            return jsonify({'message': 'MFA code sent', 'otp': otp}), 200
        else:
            session['user'] = email
            return jsonify({'message': 'Login successful'}), 200
    return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/verify-otp', methods=['POST'])
def verify_otp():
    data = request.json
    email = data['email']
    otp = data['otp']

    if email in otps and otps[email] == otp:
        session['user'] = email
        del otps[email]  # Clean up OTP
        return jsonify({'message': 'Login successful'}), 200
    return jsonify({'message': 'Invalid OTP'}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.json
    email = data['email']
    password = data['password']

    user = users.get(email)
    if user and check_password_hash(user['password'], password):
        session['user'] = email
        return jsonify({'message': 'Direct login successful'}), 200
    return jsonify({'message': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)